import os
import json
import logging
import boto3
from botocore.exceptions import ClientError

# Configure logging
logger = logging.getLogger()
logger.setLevel(logging.INFO)

# Initialize AWS clients
s3_client = boto3.client('s3')
sns_client = boto3.client('sns')

# Environment variables (set these in Lambda configuration)
OUTPUT_BUCKET_NAME = os.environ.get('OUTPUT_BUCKET_NAME')
SNS_TOPIC_ARN = os.environ.get('SNS_TOPIC_ARN')

def lambda_handler(event, context):
    logger.info(f"Received event: {json.dumps(event)}")

    # Expecting an S3 Put event
    if 'Records' not in event:
        logger.error("Event does not contain S3 records.")
        return {
            'statusCode': 400,
            'body': json.dumps('Bad Request: Event does not contain S3 records.')
        }

    for record in event['Records']:
        if 's3' not in record:
            logger.warning("Record does not contain S3 information. Skipping.")
            continue

        bucket_name = record['s3']['bucket']['name']
        object_key = record['s3']['object']['key']

        logger.info(f"Processing S3 object: {object_key} from bucket: {bucket_name}")

        try:
            # 1. Read from S3
            response = s3_client.get_object(Bucket=bucket_name, Key=object_key)
            image_content = response['Body'].read()
            logger.info(f"Successfully read object {object_key}. Content length: {len(image_content)} bytes.")

            # --- Placeholder for image processing logic ---
            # In a real application, you would perform image processing here
            # e.g., resize, watermark, analyze, etc.
            processed_data = f"Processed content for {object_key}. Original size: {len(image_content)} bytes."
            processed_file_name = f"processed-{object_key}"
            # --- End Placeholder ---

            # 2. Write results back to S3
            if not OUTPUT_BUCKET_NAME:
                logger.error("OUTPUT_BUCKET_NAME environment variable is not set.")
                raise ValueError("Output bucket name is not configured.")

            s3_client.put_object(
                Bucket=OUTPUT_BUCKET_NAME,
                Key=processed_file_name,
                Body=processed_data.encode('utf-8'), # Ensure body is bytes
                ContentType='text/plain' # Adjust content type based on actual output
            )
            logger.info(f"Successfully wrote processed data to s3://{OUTPUT_BUCKET_NAME}/{processed_file_name}")

            # 3. Send notifications via SNS
            if not SNS_TOPIC_ARN:
                logger.error("SNS_TOPIC_ARN environment variable is not set.")
                raise ValueError("SNS topic ARN is not configured.")

            sns_message = {
                'source_bucket': bucket_name,
                'source_key': object_key,
                'processed_bucket': OUTPUT_BUCKET_NAME,
                'processed_key': processed_file_name,
                'status': 'SUCCESS',
                'message': f"Image '{object_key}' processed successfully."
            }
            sns_client.publish(
                TopicArn=SNS_TOPIC_ARN,
                Message=json.dumps(sns_message),
                Subject=f"Image Processing Success: {object_key}"
            )
            logger.info(f"Successfully published SNS notification for {object_key}.")

        except ClientError as e:
            error_message = f"AWS Client Error processing {object_key}: {e}"
            logger.error(error_message)
            # Attempt to send SNS notification about the failure
            if SNS_TOPIC_ARN:
                try:
                    sns_message = {
                        'source_bucket': bucket_name,
                        'source_key': object_key,
                        'status': 'FAILED',
                        'error': str(e),
                        'message': f"Image '{object_key}' failed processing."
                    }
                    sns_client.publish(
                        TopicArn=SNS_TOPIC_ARN,
                        Message=json.dumps(sns_message),
                        Subject=f"Image Processing FAILED: {object_key}"
                    )
                    logger.info(f"Published SNS failure notification for {object_key}.")
                except ClientError as sns_e:
                    logger.error(f"Failed to publish SNS failure notification for {object_key}: {sns_e}")
            # Re-raise or return an error to indicate failure
            return {
                'statusCode': 500,
                'body': json.dumps(f'Error processing {object_key}: {str(e)}')
            }
        except Exception as e:
            error_message = f"Unexpected error processing {object_key}: {e}"
            logger.error(error_message)
            # Attempt to send SNS notification about the failure
            if SNS_TOPIC_ARN:
                try:
                    sns_message = {
                        'source_bucket': bucket_name,
                        'source_key': object_key,
                        'status': 'FAILED',
                        'error': str(e),
                        'message': f"Image '{object_key}' failed processing due to an unexpected error."
                    }
                    sns_client.publish(
                        TopicArn=SNS_TOPIC_ARN,
                        Message=json.dumps(sns_message),
                        Subject=f"Image Processing FAILED: {object_key}"
                    )
                    logger.info(f"Published SNS failure notification for {object_key}.")
                except ClientError as sns_e:
                    logger.error(f"Failed to publish SNS failure notification for {object_key}: {sns_e}")
            # Re-raise or return an error to indicate failure
            return {
                'statusCode': 500,
                'body': json.dumps(f'Unexpected error processing {object_key}: {str(e)}')
            }

    return {
        'statusCode': 200,
        'body': json.dumps('Image processing initiated successfully for all records.')
    }